function getNextSettingFileNumber() {
  let maxNum = 0;
  try {
    const files = fs.readdirSync(getConfigDir());
    files.forEach(fn => {
      const match = fn.match(/^setting-s(\d+)\.json$/);
      if (match) maxNum = Math.max(maxNum, parseInt(match[1], 10));
    });
  } catch (err) {
    _trace('CONFIG', `Scan setting files failed: ${err.message}`);
  }
  return maxNum + 1;
}

